export interface TimePhase {
    start: number;
    end: number;
    name: string;
}

export interface DayNightConfig {
    start: number;
    end: number;
    ambientColor: { r: number; g: number; b: number };
    lightIntensity: number;
}

export interface TimeEvent {
    id: string;
    hour: number;
    day: number | null;
    callback: (() => void) | null;
    triggered: boolean;
    data: Record<string, unknown>;
}

export interface TimeInfo {
    hours: number;
    minutes: number;
    formatted: string;
    day: number;
    phase: string;
    phaseName: string;
    isDay: boolean;
    isNight: boolean;
}

export class TimeSystem {
    private isInitialized: boolean = false;
    private dayTime: number = 6;
    private dayCount: number = 1;
    private timeScale: number = 1;
    private minutes: number = 0;
    private paused: boolean = false;

    private timePhases: Record<string, TimePhase> = {
        'dawn': { start: 5, end: 7, name: '黎明' },
        'morning': { start: 7, end: 11, name: '上午' },
        'noon': { start: 11, end: 13, name: '中午' },
        'afternoon': { start: 13, end: 17, name: '下午' },
        'dusk': { start: 17, end: 19, name: '黄昏' },
        'evening': { start: 19, end: 21, name: '傍晚' },
        'night': { start: 21, end: 5, name: '夜晚' },
        'midnight': { start: 0, end: 1, name: '午夜' }
    };

    private dayNightCycle: Record<string, DayNightConfig> = {
        'day': {
            start: 6,
            end: 18,
            ambientColor: { r: 255, g: 255, b: 255 },
            lightIntensity: 1.0
        },
        'night': {
            start: 18,
            end: 6,
            ambientColor: { r: 50, g: 50, b: 100 },
            lightIntensity: 0.3
        }
    };

    private timeEvents: TimeEvent[] = [];
    private lastHour: number = 6;
    private currentPhase: string = 'morning';
    private realSecondsPerGameHour: number = 60;
    private accumulatedTime: number = 0;

    constructor() {
        this.isInitialized = false;
        this.dayTime = 6;
        this.dayCount = 1;
        this.timeScale = 1;
        this.minutes = 0;
        this.lastHour = 6;
        this.currentPhase = 'morning';
        this.accumulatedTime = 0;
    }

    async init(): Promise<void> {
        console.log('[TimeSystem] 时间系统初始化完成');
        this.updatePhase();
        this.isInitialized = true;
    }

    update(deltaTime: number): void {
        if (!this.isInitialized || this.paused) return;

        this.accumulatedTime += deltaTime * this.timeScale;

        const hoursPassed = this.accumulatedTime / this.realSecondsPerGameHour;
        this.accumulatedTime = this.accumulatedTime % this.realSecondsPerGameHour;

        this.advanceTime(hoursPassed);
    }

    private advanceTime(hours: number): void {
        const oldHour = Math.floor(this.dayTime);

        this.minutes += (hours * 60) % 60;
        this.dayTime += Math.floor(hours);

        while (this.dayTime >= 24) {
            this.dayTime -= 24;
            this.dayCount++;
            // 新的一天开始（日志已禁用）
        }

        const newHour = Math.floor(this.dayTime);
        if (newHour !== oldHour) {
            this.onHourChange(oldHour, newHour);
        }
    }

    private onHourChange(oldHour: number, newHour: number): void {
        this.lastHour = oldHour;
        this.updatePhase();
        this.checkTimeEvents(newHour);
    }

    private updatePhase(): void {
        const newPhase = this.getTimePhase();
        if (newPhase !== this.currentPhase) {
            this.currentPhase = newPhase;
            // 时间阶段变化（日志已禁用）
        }
    }

    private getTimePhase(): string {
        for (const [name, phase] of Object.entries(this.timePhases)) {
            if (this.isInPhase(phase)) {
                return name;
            }
        }
        return 'night';
    }

    private isInPhase(phase: TimePhase): boolean {
        if (phase.start <= phase.end) {
            return this.dayTime >= phase.start && this.dayTime < phase.end;
        } else {
            return this.dayTime >= phase.start || this.dayTime < phase.end;
        }
    }

    private checkTimeEvents(hour: number): void {
        for (const event of this.timeEvents) {
            if (event.hour === hour && !event.triggered) {
                if (event.day ? event.day === this.dayCount : true) {
                    event.triggered = true;
                    if (event.callback) {
                        event.callback();
                    }
                }
            }
        }
    }

    addTimeEvent(config: { id?: string; hour: number; day?: number | null; callback?: (() => void) | null; data?: Record<string, unknown> }): TimeEvent {
        const event: TimeEvent = {
            id: config.id || `event_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            hour: config.hour,
            day: config.day !== undefined ? config.day : null,
            callback: config.callback || null,
            triggered: false,
            data: config.data || {}
        };
        this.timeEvents.push(event);
        return event;
    }

    removeTimeEvent(eventId: string): void {
        const index = this.timeEvents.findIndex(e => e.id === eventId);
        if (index !== -1) {
            this.timeEvents.splice(index, 1);
        }
    }

    getTimeString(): string {
        const hours = Math.floor(this.dayTime);
        const mins = Math.floor(this.minutes);
        return `${hours.toString().padStart(2, '0')}:${mins.toString().padStart(2, '0')}`;
    }

    getTimeInfo(): TimeInfo {
        return {
            hours: Math.floor(this.dayTime),
            minutes: Math.floor(this.minutes),
            formatted: this.getTimeString(),
            day: this.dayCount,
            phase: this.currentPhase,
            phaseName: this.timePhases[this.currentPhase]?.name || '未知',
            isDay: this.isDay(),
            isNight: this.isNight()
        };
    }

    isDay(): boolean {
        return this.dayTime >= this.dayNightCycle.day.start &&
               this.dayTime < this.dayNightCycle.day.end;
    }

    isNight(): boolean {
        return !this.isDay();
    }

    getAmbientColor(): { r: number; g: number; b: number } {
        if (this.isDay()) {
            return { ...this.dayNightCycle.day.ambientColor };
        } else {
            return { ...this.dayNightCycle.night.ambientColor };
        }
    }

    getLightIntensity(): number {
        const targetIntensity = this.isDay()
            ? this.dayNightCycle.day.lightIntensity
            : this.dayNightCycle.night.lightIntensity;

        if (this.currentPhase === 'dawn' || this.currentPhase === 'dusk') {
            const phase = this.timePhases[this.currentPhase];
            const progress = (this.dayTime - phase.start) / (phase.end - phase.start);
            const dayIntensity = this.dayNightCycle.day.lightIntensity;
            const nightIntensity = this.dayNightCycle.night.lightIntensity;

            if (this.currentPhase === 'dawn') {
                return nightIntensity + (dayIntensity - nightIntensity) * progress;
            } else {
                return dayIntensity - (dayIntensity - nightIntensity) * progress;
            }
        }

        return targetIntensity;
    }

    setTime(hours: number, minutes: number = 0): void {
        const oldHour = Math.floor(this.dayTime);
        this.dayTime = hours + minutes / 60;
        this.minutes = minutes % 60;
        const newHour = Math.floor(this.dayTime);

        while (this.dayTime >= 24) {
            this.dayTime -= 24;
            this.dayCount++;
        }

        if (newHour !== oldHour) {
            this.onHourChange(oldHour, newHour);
        }

        console.log(`[TimeSystem] 时间设置为: ${this.getTimeString()}`);
    }

    setDay(day: number): void {
        this.dayCount = day;
        console.log(`[TimeSystem] 天数设置为: 第${this.dayCount}天`);
    }

    advanceDay(days: number = 1): void {
        this.dayCount += days;
        console.log(`[TimeSystem] 天数增加: 第${this.dayCount}天`);
        this.resetDailyEvents();
    }

    private resetDailyEvents(): void {
        for (const event of this.timeEvents) {
            if (event.day === null) {
                event.triggered = false;
            }
        }
    }

    setTimeScale(scale: number): void {
        this.timeScale = scale;
        console.log(`[TimeSystem] 时间流逝速度设置为: ${scale}x`);
    }

    getTimeScale(): number {
        return this.timeScale;
    }

    getCurrentPhase(): string {
        return this.currentPhase;
    }

    getPhaseInfo(phaseName: string): TimePhase | null {
        return this.timePhases[phaseName] || null;
    }

    pause(): void {
        this.paused = true;
        console.log('[TimeSystem] 时间系统已暂停');
    }

    resume(): void {
        this.paused = false;
        console.log('[TimeSystem] 时间系统已恢复');
    }

    togglePause(): void {
        if (this.paused) {
            this.resume();
        } else {
            this.pause();
        }
    }

    reset(): void {
        this.dayTime = 6;
        this.dayCount = 1;
        this.minutes = 0;
        this.timeScale = 1;
        this.accumulatedTime = 0;
        this.timeEvents = [];
        this.lastHour = 6;
        this.currentPhase = 'morning';
        console.log('[TimeSystem] 时间系统已重置');
    }

    getStats(): {
        dayCount: number;
        currentTime: string;
        currentPhase: string;
        timeScale: number;
        totalHoursPlayed: number;
        pendingEvents: number;
    } {
        return {
            dayCount: this.dayCount,
            currentTime: this.getTimeString(),
            currentPhase: this.currentPhase,
            timeScale: this.timeScale,
            totalHoursPlayed: (this.dayCount - 1) * 24 + this.dayTime,
            pendingEvents: this.timeEvents.filter(e => !e.triggered).length
        };
    }
}

export default TimeSystem;
